        }
        50% {
          transform: translate3d(-0.8%, 0.6%, 0) scale(1.01);
        }
        100% {
          transform: translate3d(0, 0, 0) scale(1);
        }
      }

      .star-canvas {
        position: absolute;
        inset: 0;
        width: 100%;
        height: 100%;
        border-radius: inherit;
