      }

      .particles i {
        position: absolute;
        top: 50%;
        left: 50%;
        width: var(--size, 2px);
        height: var(--size, 2px);
        border-radius: 50%;
        background: radial-gradient(circle at 50% 50%, #fff 0%, #efe9ff 45%, rgba(255, 255, 255, 0) 70%);
