         * 直接调用系统Slash命令进行发送和触发回复
         */
        function sendSillyTavernCommand(textToSend) {
            // 如果内容为空则跳过
            if (!textToSend) return;

            const commandChain = [];
            // 转义双引号以防JS报错
            const message = textToSend.replace(/"/g, '\\"');

            // 构建指令: 发送内容 并 触发等待回复
            commandChain.push(`/send ${message}`);
            commandChain.push('/trigger await=true');

            const finalCommand = commandChain.join(' | ');

            // 尝试在不同层级寻找 triggerSlash 函数
            if (typeof triggerSlash === 'function') {
                triggerSlash(finalCommand);
            }
            else if (window.parent && typeof window.parent.triggerSlash === 'function') {
                window.parent.triggerSlash(finalCommand);
            }
            else {
                // 兼容性后备方案：如果找不到 triggerSlash，尝试传统的填入输入框方式
                console.warn("SillyTavern Slash API not found, falling back to clipboard/input.");
                try {
                    const inputArea = window.parent.document.querySelector('#send_textarea');
                    if (inputArea) {
                        const ev = new Event('input', { bubbles: true});
                        inputArea.value = textToSend;
                        inputArea.dispatchEvent(ev);
                        // 尝试自动点击发送按钮
                        const sendBtn = window.parent.document.querySelector('#send_butt');
                        if(sendBtn) sendBtn.click();
                    }
                } catch(e) {
                    alert(`指令模式不可用:\n${finalCommand}`);
                }
            }
        }

        document.addEventListener('DOMContentLoaded', () => {
            // 为每个按钮绑定点击事件
            document.querySelectorAll('.era-action-btn').forEach(btn => {
                btn.addEventListener('click', function() {
                    const text = this.innerText.trim();
