                    console.warn('SillyTavern UI 链接失败:', error);
                    // 降级处理：仅在控制台输出或复制到剪贴板
                }
            };

            // 绑定按钮事件
            document.querySelectorAll('.era-action-btn').forEach(btn => {
                btn.addEventListener('click', function() {
                    // 获取按钮文本，移除可能存在的图标HTML标签，只保留文字
                    const text = this.innerText.trim();
                    if(text) handleSend(text);

                    // 点击反馈动画
                    this.style.transform = 'scale(0.95)';
                    setTimeout(() => this.style.transform = '', 150);
                });
            });
        });
    </script>
